def convert_base(value, from_base, to_base):
    """将value从from_base进制转换为to_base进制，返回字符串"""
    # 先转换为十进制整数
    decimal = int(value, from_base) if isinstance(value, str) else value
    # 再转换为目标进制
    if to_base == 10:
        return str(decimal)
    elif to_base == 2:
        return bin(decimal)[2:]
    elif to_base == 8:
        return oct(decimal)[2:]
    elif to_base == 16:
        return hex(decimal)[2:]
    else:
        # 通用转换（2-36进制）
        digits = '0123456789abcdefghijklmnopqrstuvwxyz'
        result = ''
        if decimal == 0:
            return '0'
        while decimal > 0:
            result = digits[decimal % to_base] + result
            decimal //= to_base
        return result
